package com.example.mfa.security;

import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Component;

import java.security.SecureRandom;
import java.util.Base64;

@Component
class SecuritySupport {
    private final PasswordEncoder passwordEncoder = new BCryptPasswordEncoder();
    private final SecureRandom secureRandom = new SecureRandom();

    PasswordEncoder passwordEncoder() {
        return passwordEncoder;
    }

    String hashBackupCode(String code) {
        return passwordEncoder.encode(code);
    }

    boolean matchesBackupCode(String rawCode, String hash) {
        return passwordEncoder.matches(rawCode, hash);
    }

    String generateMfaSecret() {
        byte[] bytes = new byte[20];
        secureRandom.nextBytes(bytes);
        return Base64.getEncoder().withoutPadding().encodeToString(bytes);
    }

    String generateBackupCode() {
        byte[] bytes = new byte[9];
        secureRandom.nextBytes(bytes);
        String token = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase();
        return token.substring(0, Math.min(12, token.length()));
    }
}

package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.BackupCode;
import com.example.mfa.repo.BackupCodeRepository;
import com.example.mfa.repo.UserRepository;
import com.example.mfa.security.SecuritySupport;
import jakarta.transaction.Transactional;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Service
class MfaService {
    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final SecuritySupport securitySupport;

    MfaService(UserRepository userRepository, BackupCodeRepository backupCodeRepository, SecuritySupport securitySupport) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.securitySupport = securitySupport;
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(UUID userId, int codeCount) {
        AppUser user = userRepository.findById(userId).orElseThrow();
        user.setMfaEnabled(true);
        user.setMfaSecret(securitySupport.generateMfaSecret());

        backupCodeRepository.deleteAll(backupCodeRepository.findByUserIdAndUsedFalse(userId));

        List<String> rawCodes = new ArrayList<>();
        for (int i = 0; i < codeCount; i++) {
            String raw = generateUniqueBackupCode(userId);
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(securitySupport.hashBackupCode(raw));
            code.setUsed(false);
            backupCodeRepository.save(code);
            rawCodes.add(raw);
        }
        return rawCodes;
    }

    @Transactional
    public boolean authenticateWithBackupCode(UUID userId, String rawBackupCode) {
        AppUser user = userRepository.findById(userId).orElseThrow();
        if (!user.isMfaEnabled()) {
            return false;
        }
        List<BackupCode> candidates = backupCodeRepository.findByUserIdAndUsedFalse(userId);
        for (BackupCode code : candidates) {
            if (securitySupport.matchesBackupCode(rawBackupCode, code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    @Transactional
    public List<String> regenerateBackupCodes(UUID userId, int codeCount) {
        backupCodeRepository.deleteAll(backupCodeRepository.findByUserIdAndUsedFalse(userId));
        return enableMfaAndGenerateBackupCodes(userId, codeCount);
    }

    private String generateUniqueBackupCode(UUID userId) {
        while (true) {
            String raw = securitySupport.generateBackupCode();
            boolean exists = backupCodeRepository.findByUserIdAndCodeHashAndUsedFalse(userId, securitySupport.hashBackupCode(raw)).isPresent();
            if (!exists) {
                return raw;
            }
        }
    }
}

package com.example.mfa.web;

import com.example.mfa.repo.UserRepository;
import com.example.mfa.service.MfaService;
import jakarta.validation.constraints.Min;
import jakarta.validation.constraints.NotBlank;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.UUID;

@RestController
@RequestMapping("/api/mfa")
class MfaController {
    private final MfaService mfaService;
    private final UserRepository userRepository;

    MfaController(MfaService mfaService, UserRepository userRepository) {
        this.mfaService = mfaService;
        this.userRepository = userRepository;
    }

    @PostMapping("/enable/{userId}")
    public ResponseEntity<EnableMfaResponse> enable(@PathVariable UUID userId, @RequestBody EnableMfaRequest request) {
        userRepository.findById(userId).orElseThrow();
        List<String> codes = mfaService.enableMfaAndGenerateBackupCodes(userId, request.codeCount());
        return ResponseEntity.ok(new EnableMfaResponse("MFA enabled", codes));
    }

    @PostMapping("/backup/authenticate/{userId}")
    public ResponseEntity<BackupAuthResponse> authenticateWithBackupCode(@PathVariable UUID userId, @RequestBody BackupAuthRequest request) {
        boolean success = mfaService.authenticateWithBackupCode(userId, request.backupCode());
        return ResponseEntity.ok(new BackupAuthResponse(success));
    }

    @PostMapping("/backup/regenerate/{userId}")
    public ResponseEntity<EnableMfaResponse> regenerate(@PathVariable UUID userId, @RequestBody EnableMfaRequest request) {
        List<String> codes = mfaService.regenerateBackupCodes(userId, request.codeCount());
        return ResponseEntity.ok(new EnableMfaResponse("Backup codes regenerated", codes));
    }

    record EnableMfaRequest(@Min(1) int codeCount) {}
    record BackupAuthRequest(@NotBlank String backupCode) {}
    record EnableMfaResponse(String message, List<String> backupCodes) {}
    record BackupAuthResponse(boolean authenticated) {}
}

